```class Solution {
public:
    string smallestSubsequence(string s) {
        string res;
        unordered_map<char, int> last;
        for (int i = 0; i < s.size(); i++) {
            last[s[i]] = i;
        }
        priority_queue<char, vector<char>, greater<char>> pq;
        for (char c : s) {
            if (pq.size() && pq.top() < c) {
                res += pq.top();
                pq.pop();
            }
            pq.push(c);
            last[c]--;
            if (last[c] == 0) {
                last.erase(c);
            }
        }
        while (!pq.empty()) {
            res += pq.top();
            pq.pop();
        }
        return res;
    }
};```
